; field_moves.asm — field-move static data.
;
; Holds the shared FieldMoveDisplayData / FieldMoveNames tables (generated by
; tools/gen_field_moves.py from data/moves/{field_moves,field_move_names}.asm).
; These are pret's own tables, and their only consumers are the two pret routines
; that own them, both in src/engine/menus/text_box.asm:
;   * GetMonFieldMoves      — scans FieldMoveDisplayData ($FF-terminated, 3-byte
;                             records) for each of the mon's moves.
;   * DisplayFieldMoveMonMenu — walks FieldMoveNames to print them.
;
; This file is DATA ONLY. It used to also export a port-only helper, IsFieldMove
; — a second, hand-written scan of the same table, written when the party menu
; labelled field moves itself. Commit c0b225ac ("party menu realigned onto the
; faithful pret split") replaced that call with pret's GetMonFieldMoves and left
; IsFieldMove with no callers anywhere in the tree, while this header went on
; asserting "party_menu.asm calls IsFieldMove" for the entire time. Verified at
; menu-fidelity row 13 (grep + nm: linked, called by nobody) and deleted, so the
; port has exactly one field-move scan and it is pret's. See M-50.
;
; The data must live in a LINKED source (text_box.asm is in GAME_SRCS), so it is
; its own module rather than riding battle_data.asm (BATTLE_SRCS, not yet linked).
; Embedded data goes in .data per the linker rule in docs/assembly.md (.rodata has
; no output-section rule → reads back as zero).
;
; Build: nasm -f coff -I include/ -I . -o field_moves.o field_moves.asm
; ---------------------------------------------------------------------------
bits 32

%include "gb_constants.inc"

global FieldMoveDisplayData
global FieldMoveNames

section .data
align 4
%include "assets/field_moves.inc"
